            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterByteArray.allocationSize(value.`privateKeyPem`)
            )
        }
    }

    override fun write(value: SshAuth, buf: ByteBuffer) {
        when(value) {
